-- ============================================================================
-- live-import-demo-tenant.sql  (regenerado 2026-06-15)
-- Importa el tenant "demo" (SistecPOS demo) desde Test a Live.
-- Ejecutar en: Lovable Cloud → Backend → Run SQL  (con LIVE seleccionado)
-- Pre-requisitos:
--   1) Publish/Update aplicado en Live (incluye export/import_tenant_snapshot).
--   2) Estar logueado como superadmin maestro (edurdotp77@gmail.com).
--   3) (Opcional) Crear primero el usuario owner demo@sistecpos.com vía
--      Backend → Authentication → Add user.  Si no existe, el import
--      saltará organization_members (queda log en tenant_audit_log) y luego
--      puedes correr el bloque "OWNER FIXUP" al final.
-- ============================================================================

-- ============================================================================
-- PRE-SEED: catálogo public.modules (idempotente)
-- Necesario porque organization_modules.module_key tiene FK contra modules(key)
-- y el snapshot del tenant demo referencia: retail, pos, inventario, crm, mesas,
-- kds, horeca, agenda, licencias, whatsapp, fiscal, compras, belleza, spa,
-- representantes. Si Live no tiene la tabla poblada, el import falla con 23503.
-- ============================================================================
INSERT INTO public.modules (key, name, description, category, icon, is_active, sort_order) VALUES
  ('retail',         'Retail / Tienda',          'Catálogo, ventas y caja para tiendas minoristas.',        'core',       'store',           true, 10),
  ('horeca',         'HORECA',                   'Restaurantes, bares y cafés: mesas, comandas, cocina.',   'core',       'utensils',        true, 20),
  ('pos',            'POS / Caja',               'Punto de venta para mostrador con impresión y pagos.',    'operations', 'monitor',         true, 30),
  ('kds',            'KDS Cocina',               'Pantalla de cocina con ruteo por estación.',              'operations', 'chef-hat',        true, 40),
  ('mesas',          'Mesas',                    'Gestión de áreas, mesas y cuentas abiertas.',             'operations', 'grid-3x3',        true, 50),
  ('inventario',     'Inventario',               'Stock, bodegas, transferencias y movimientos.',           'operations', 'package',         true, 60),
  ('agenda',         'Agenda / Citas',           'Reserva de citas y recursos.',                            'verticals',  'calendar-days',   true, 70),
  ('spa',            'Spa & Bienestar',          'Servicios, paquetes y comisiones para spa.',              'verticals',  'flower',          true, 80),
  ('belleza',        'Belleza & Estética',       'Salones y centros de belleza.',                           'verticals',  'sparkles',        true, 90),
  ('representantes', 'Representantes',           'Fuerza de ventas en calle con catálogo offline.',         'crm',        'briefcase',       true, 100),
  ('crm',            'CRM Leads',                'Captura y seguimiento de prospectos.',                    'crm',        'users',           true, 110),
  ('licencias',      'Licencias Desktop',        'Emisión y control de licencias del POS de escritorio.',   'admin',      'key-round',       true, 120),
  ('whatsapp',       'WhatsApp',                 'Integración con WhatsApp Cloud API.',                     'operations', 'message-circle',  true, 130),
  ('fiscal',         'Facturación electrónica',  'DIAN: facturación electrónica y documentos soporte.',     'admin',      'file-text',       true, 140),
  ('compras',        'Compras / Proveedores',    'Órdenes de compra y gestión de proveedores.',             'operations', 'truck',           true, 150)
ON CONFLICT (key) DO UPDATE SET
  name        = EXCLUDED.name,
  description = EXCLUDED.description,
  category    = EXCLUDED.category,
  icon        = EXCLUDED.icon,
  is_active   = EXCLUDED.is_active,
  sort_order  = EXCLUDED.sort_order;

-- ============================================================================
-- HOTFIX: trigger auto_create_base_presentation no propaga organization_id
-- product_presentations.organization_id es NOT NULL → import falla 23502.
-- Parchamos la función antes del import (idempotente).
-- ============================================================================
CREATE OR REPLACE FUNCTION public.auto_create_base_presentation()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $func$
BEGIN
  INSERT INTO public.product_presentations
    (product_id, organization_id, name, conversion_factor, price, sort_order, is_active)
  VALUES
    (NEW.id, NEW.organization_id, COALESCE(NEW.base_unit, 'unidad'), 1, NEW.price, 0, true);
  RETURN NEW;
END;
$func$;

